class Queue<T> {
  private items: T[] = [];

  enqueue(item: T): void { this.items.push(item); }
  dequeue(): T | undefined { return this.items.shift(); }
  peek(): T | undefined   { return this.items[0]; }
  size(): number          { return this.items.length; }
  isEmpty(): boolean      { return this.items.length === 0; }
}

const taskQueue = new Queue<string>();
taskQueue.enqueue("send email");
taskQueue.enqueue("process payment");
taskQueue.enqueue("update database");

console.log(`Tasks: ${taskQueue.size()}`);
console.log(`Next: ${taskQueue.peek()}`);
console.log(`Processed: ${taskQueue.dequeue()}`);
console.log(`Remaining: ${taskQueue.size()}`);

interface ApiResponse<T> {
  success: boolean;
  data: T | null;
  error: string | null;
}

function ok<T>(data: T): ApiResponse<T> {
  return { success: true, data, error: null };
}

function err<T>(message: string): ApiResponse<T> {
  return { success: false, data: null, error: message };
}

