interface EventEmitter<TEvents extends Record<string, unknown>> {
  on<K extends keyof TEvents>(event: K, handler: (data: TEvents[K]) => void): void;
  emit<K extends keyof TEvents>(event: K, data: TEvents[K]): void;
}

interface UserEvents {
  login:  { userId: number; timestamp: string };
  logout: { userId: number };
}

class SimpleEmitter<T extends Record<string, unknown>> implements EventEmitter<T> {
  private handlers: Partial<Record<keyof T, Array<(d: unknown) => void>>> = {};
  on<K extends keyof T>(event: K, handler: (d: T[K]) => void): void {
    const existing = (this.handlers[event] as Array<(d: unknown) => void>) ?? [];
    existing.push(handler as (d: unknown) => void);
    this.handlers[event] = existing;
  }
  emit<K extends keyof T>(event: K, data: T[K]): void {
    const hs = (this.handlers[event] as Array<(d: unknown) => void>) ?? [];
    for (const h of hs) h(data);
  }
}

const emitter = new SimpleEmitter<UserEvents>();
emitter.on("login",  e => console.log(`Login: user ${e.userId}`));
emitter.on("logout", e => console.log(`Logout: user ${e.userId}`));
emitter.emit("login",  { userId: 42, timestamp: "2024-01-15" });
emitter.emit("logout", { userId: 42 });

function getOrDefault<T>(value: T | null | undefined, defaultValue: T): T {
  return value ?? defaultValue;
}

function coerce<T extends string | number | boolean>(
  value: unknown,
  type: "string" | "number" | "boolean"
): T {
  switch (type) {
    case "string":  return String(value) as T;
    case "number":  return Number(value) as T;
    case "boolean": return Boolean(value) as T;
  }
}

// getOrDefault infers T from the default value type
console.log(getOrDefault(null, "default value"));
console.log(getOrDefault(undefined, 42));
console.log(getOrDefault("provided", "default"));
console.log(getOrDefault(0, 100));  // 0 is falsy but not null/undefined

console.log(coerce<number>("42", "number"));
console.log(coerce<string>(123, "string"));

function pipe<T>(value: T): T;
function pipe<A, B>(value: A, fn1: (a: A) => B): B;
function pipe<A, B, C>(value: A, fn1: (a: A) => B, fn2: (b: B) => C): C;
function pipe<A, B, C, D>(value: A, fn1: (a: A) => B, fn2: (b: B) => C, fn3: (c: C) => D): D;
function pipe(value: unknown, ...fns: Array<(v: unknown) => unknown>): unknown {
  return fns.reduce((v, fn) => fn(v), value);
}

const result = pipe(
  "  Hello, World!  ",
  (s: string) => s.trim(),
  (s: string) => s.toLowerCase(),
  (s: string) => s.replace(/,\s*/g, "-"),
  (s: string) => s.replace(/!/g, "")
);

console.log(result);

type Result<T, E = Error> =
  | { success: true;  value: T }
  | { success: false; error: E };

function succeed<T>(value: T): Result<T> {
  return { success: true, value };
}

function fail<T, E = Error>(error: E): Result<T, E> {
  return { success: false, error } as Result<T, E>;
}

function mapResult<T, U, E>(r: Result<T, E>, fn: (v: T) => Result<U, E>): Result<U, E> {
  return r.success ? fn(r.value) : r;
}

function parseAge(s: string): Result<number> {
  const n = parseInt(s, 10);
  if (isNaN(n)) return fail(new Error(`"${s}" is not a number`));
  if (n < 0)    return fail(new Error(`Age must be non-negative`));
  return succeed(n);
}

const inputs = ["25", "-1", "abc", "42"];
for (const input of inputs) {
  const result = parseAge(input);
  console.log(result.success ? `✓ ${result.value}` : `✗ ${result.error.message}`);
}

function memoize<TArgs extends unknown[], TReturn>(
  fn: (...args: TArgs) => TReturn
): (...args: TArgs) => TReturn {
  const cache = new Map<string, TReturn>();
  return (...args: TArgs) => {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key)!;
    const result = fn(...args);
    cache.set(key, result);
    return result;
  };
}

function fibonacci(n: number): number {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
}

const memoFib = memoize(fibonacci);

for (const n of [10, 15, 20, 25]) {
  console.log(`fib(${n}) = ${memoFib(n)}`);
}

function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

function setProperty<T, K extends keyof T>(obj: T, key: K, value: T[K]): T {
  return { ...obj, [key]: value };
}

function pick<T, K extends keyof T>(obj: T, keys: K[]): Pick<T, K> {
  const result = {} as Pick<T, K>;
  for (const key of keys) result[key] = obj[key];
  return result;
}

const user = { id: 1, name: "Alice", email: "alice@co.com", plan: "pro", xp: 2850 };

console.log(getProperty(user, "name"));
console.log(getProperty(user, "xp"));

const updated = setProperty(user, "plan", "enterprise");
